189→    /**
190→     * 重发背调邮件.
191→     */
192→    public function resend(array $input): array
193→    {
194→        $id = (int)Arr::get($input, 'background_check_id');
195→        $record = BackgroundCheckRecordMd::find($id);
196→        if (!$record) {
197→            throw new \App\Exceptions\UserException(__('my_api.background_check_record_not_found'), \App\Exceptions\ExceptionCode::USER_INVALID_INPUT);
198→        }
199→
200→        $newEmail = Arr::get($input, 'background_check_email', $record->background_check_email);
201→        $newEmailSearch = Arr::get($input, 'email_search', $record->email_search ?? '');
202→        $record->update([
203→            'background_check_email' => $newEmail,
204→            'email_search' => $newEmailSearch,
205→            'sent_at' => now(),
206→        ]);
207→        // 同步更新关联 inquiry 的 email_search
208→        BackgroundCheckInquiryMd::where('background_check_record_id', $record->id)
209→            ->update(['background_check_email' => $newEmail, 'email_search' => $newEmailSearch]);
210→
211→        return ['id' => $record->id, 'success' => true];
212→    }
