230→    /**
231→     * 根据背调记录 ID 获取背调授权书附件信息（供 mail/send 使用，避免前端传加密 path）.
232→     */
233→    public function getBackgroundCheckAuthFileForMail(int $backgroundCheckId): ?array
234→    {
235→        Log::info('[背调附件] getBackgroundCheckAuthFileForMail background_check_id='.$backgroundCheckId);
236→        $record = BackgroundCheckRecordMd::find($backgroundCheckId);
237→        if (!$record) {
238→            Log::warning('[背调附件] 背调记录不存在 background_check_id='.$backgroundCheckId);
239→            return null;
240→        }
241→        Log::info('[背调附件] 背调记录 resume_id='.$record->resume_id);
242→        return $this->getBackgroundCheckAuthFile($record->resume_id);
243→    }
244→
245→    private function getWorkExperienceByIndex(array $experiences, int $index): ?array
246→    {
247→        $workList = array_values(array_filter((array)$experiences, function ($e) {
248→            $e = is_array($e) ? $e : (array)$e;
249→            return strtolower(trim($e['type'] ?? '')) === 'work';
250→        }));
251→        if (empty($workList) || $index < 1 || $index > count($workList)) {
252→            return null;
253→        }
254→        usort($workList, function ($a, $b) {
255→            $a = is_array($a) ? $a : (array)$a;
256→            $b = is_array($b) ? $b : (array)$b;
257→            $endA = strtotime($a['end_time'] ?? $a['start_time'] ?? '0');
258→            $endB = strtotime($b['end_time'] ?? $b['start_time'] ?? '0');
259→            return $endB <=> $endA;
260→        });
261→        return $workList[$index - 1] ?? null;
262→    }
263→
264→    /**
265→     * 从录用材料中获取背调授权书文件（type=backgroundCheck）.
266→     * @return null|array{disk: string, file_store_path: string, file_real_name: string}
267→     */
268→    private function getBackgroundCheckAuthFile(int $resumeId): ?array
269→    {
270→        Log::info('[背调附件] getBackgroundCheckAuthFile resume_id='.$resumeId);
271→        $or = OnboardingReviewMd::where('resume_id', $resumeId)->orderBy('id', 'desc')->first();
272→        if (!$or) {
273→            Log::warning('[背调附件] 未找到 onboarding_review resume_id='.$resumeId);
274→            return null;
275→        }
276→        Log::info('[背调附件] onboarding_review id='.$or->id);
277→        $file = FileStorePathMd::where('table_name', 'onboarding_review')
278→            ->where('table_id', $or->id)
279→            ->where('type', 'backgroundCheck')
280→            ->where('is_on', 1)
281→            ->first();
282→        if (!$file) {
283→            Log::warning('[背调附件] 未找到 type=backgroundCheck 文件 table_id='.$or->id);
284→            return null;
285→        }
286→        Log::info('[背调附件] FileStorePath id='.$file->id.', disk='.$file->disk.', file_store_path='.$file->file_store_path);
287→        return [
288→            'disk' => $file->disk ?: 'onboarding_review',
289→            'file_store_path' => $file->file_store_path,
290→            'file_real_name' => $file->file_real_name ?? '',
291→        ];
292→    }
293→
294→    private function getWorkExpPositionDefault(array $workExp): string
295→    {
296→        if (!empty($workExp['position'])) {
297→            return $workExp['position'];
298→        }
299→        $desc = $workExp['description'] ?? '';
300→        if ($desc) {
301→            $parts = explode(' | ', $desc);
302→            return $parts[0] ?? '';
303→        }
304→        return '';
305→    }
306→}
